  if (this.props.selectsRange) {
    ariaLiveMessage = `Selected start date: ${safeDateFormat(
      this.props.startDate,
      {
        dateFormat: longDateFormat,
        locale,
      },
    )}. ${
      this.props.endDate
        ? "End date: " +
