    } else if (this.props.showQuarterYearPicker) {
      ariaLiveMessage = `Selected quarter: ${safeDateFormat(
        this.props.selected,
        {
          dateFormat: "yyyy, QQQ",
          locale,
        },
      )}`;
    } else {
      ariaLiveMessage = `Selected date: ${safeDateFormat(
        this.props.selected,
        {
          dateFormat: longDateFormat,
          locale,
        },
      )}`;
    }
  }

  return (
    <span
      role="alert"
      aria-live="polite"
      className="react-datepicker__aria-live"
