isCurrentMonth = (day: Date, m: number) =>
  getYear(day) === getYear(newDate()) && m === getMonth(newDate());

isCurrentQuarter = (day: Date, q: number) =>
  getYear(day) === getYear(newDate()) && q === getQuarter(newDate());

